import React, { useState } from "react";
import { Link } from "react-router-dom";
import { removeProduct } from "../../../redux/cartRedux";
import { useDispatch, useSelector } from "react-redux";

const pStyle = {
  WebkitBoxOrient: "vertical",
  WebkitLineClamp: "2",
  display: "-webkit-box",
  whiteSpace: "normal",
  overflow: "hidden",
};

const FilledCart = (props) => {
  const dispatch = useDispatch();
  const clickHandler = (e) => {
    if (props.data.quantity > 0) {
      dispatch(
        removeProduct({
          id: e.target.getAttribute("productid"),
          price: e.target.getAttribute("price"),
        })
      );
    }
  };
  return (
    <div className="row mt-4">
      <div
        className="col-12 col-lg  me-3 p-3"
        style={{
          backgroundColor: "white",
          boxShadow: "0 2px 5px 0 rgb(0 0 0 / 5%)",
          borderRadius: "5px",
        }}
      >
        <div className="row">
          <h5 className="pb-3" style={{ borderBottom: "1px solid #ededed" }}>
            Cart ({props.data.products.length})
          </h5>
        </div>
        {props.data.products.map((data, i) => {
          return (
            <div>
              <div
                className="row p-3"
                style={{ borderBottom: "1px solid #ededed" }}
              >
                <div className="col-3 col-md-2">
                  <Link to={`/product/${data.id}`}>
                    <img width="70" src={data.thumbnail}></img>
                  </Link>
                  <Link to='/cart'

                    price={data.price}
                    productid={data.id}
                    onClick={clickHandler}
                  >
                    <p
                      price={data.price}
                      productid={data.id}
                      className="text-danger pt-2"
                      style={{ fontSize: "18px" }}
                    >
                      <i
                        price={data.price}
                        productid={data.id}
                        className="fa fa-trash"
                      ></i>{" "}
                      Remove
                    </p>
                  </Link>
                </div>
                <div className="col-6 col-md-8">
                  <p style={pStyle}>{data.title}</p>
                </div>
                <div
                  className="col-3 col-md-2"
                  style={{
                    display: "flex",
                    flexDirection: "column",
                    justifyContent: "space-between",
                    alignItems: "center",
                  }}
                >
                  <p
                    style={{ fontWeight: "500", fontSize: "1rem" }}
                  >{`EGP ${data.price}`}</p>
                  <div>
                    <p
                      style={{ fontWeight: "500", margin: "0" }}
                    >{`Quantity`}</p>
                    <p
                      style={{
                        width: "100%",
                        color: "#0d6efd",
                        fontSize: "20px",
                        fontWeight: "bold",
                        textAlign: "center",
                        margin: "0",
                      }}
                    >
                      (1)
                    </p>
                  </div>
                </div>
              </div>
            </div>
          );
        })}
      </div>
      <div className="col-12 col-lg-3 mt-3 mt-lg-0">
        <div
          className="row p-3"
          style={{
            backgroundColor: "white",
            boxShadow: "0 2px 5px 0 rgb(0 0 0 / 5%)",
            borderRadius: "5px",
          }}
        >
          <div className="col-12">
            <div className="row">
              <h6
                className="pb-3"
                style={{ borderBottom: "1px solid #ededed" }}
              >
                CART SUMMARY
              </h6>
            </div>
            <div
              className="row justify-content-between pt-2 pb-2"
              style={{ borderBottom: "1px solid #ededed" }}
            >
              <h6 className=" col-4">Subtotal</h6>
              <p
                className="col-8 text-end"
                style={{ fontWeight: "500", margin: "0", fontSize: "1.25rem" }}
              >
                {props.data.total} EGP
              </p>
            </div>
            <div className="row">
              <Link className="btn btn-primary" to="/checkout">
                CHECKOUT ({props.data.total})
              </Link>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default FilledCart;
