import React from "react";
import { useSelector } from "react-redux";

const pStyle = {
  WebkitBoxOrient: "vertical",
  WebkitLineClamp: "1",
  display: "-webkit-box",
  whiteSpace: "normal",
  overflow: "hidden",
  margin: "0",
};

const Checkout = () => {
  const cart = useSelector((state) => state.cart);
  return (
    <div className="pt-5 pb-5" style={{ backgroundColor: "#ebeef5" }}>
      <div className="container">
        <div className="row">
          <h6 className="col-12" style={{ color: "#ababab", padding: "0" }}>
            CHECKOUT
          </h6>
        </div>
        <div className="row">
          <div
            className="col-12 col-md me-3 p-3"
            style={{
              backgroundColor: "white",
              boxShadow: "0 2px 5px 0 rgb(0 0 0 / 5%)",
              borderRadius: "5px",
            }}
          >
            <h6 className="pb-3" style={{ borderBottom: "1px solid #ededed" }}>
              <i
                style={{ color: "#ababab", fontSize: "1.25rem" }}
                className="fa fa-check-circle pe-4"
                aria-hidden="true"
              ></i>{" "}
              1. ADDRESS DETAILS
            </h6>

            <div className="row">
              <form className="p-4">
                <div className="row">
                  <div className="mb-3 col-6">
                    <label className="form-label">First Name</label>
                    <input type="text" className="form-control" />
                  </div>
                  <div className="mb-3 col-6">
                    <label className="form-label">Last Name</label>
                    <input type="text" className="form-control" />
                  </div>
                </div>
                <div className="mb-3">
                  <label className="form-label">Phone</label>
                  <input type="number" className="form-control" />
                </div>
                <div className="mb-3">
                  <label className="form-label">Email</label>
                  <input type="email" className="form-control" />
                </div>

                <div className="mb-3">
                  <label className="form-label">Adress</label>
                  <textarea type="text" className="form-control" />
                </div>

                <div className="mb-3">
                  <label className="form-label">More Address Information</label>
                  <textarea type="text" className="form-control" />
                </div>
              </form>
            </div>
          </div>
          <div className="col-12 col-md-3 mt-3 mt-md-0">
            <div
              className="row p-3"
              style={{
                backgroundColor: "white",
                boxShadow: "0 2px 5px 0 rgb(0 0 0 / 5%)",
                borderRadius: "5px",
              }}
            >
              <div className="col-12">
                <h6
                  className="pb-3"
                  style={{ borderBottom: "1px solid #ededed" }}
                >
                  Your Order ({cart.products.length})
                </h6>
                {cart.products.map((product, i) => {
                  return (
                    <div className="row align-items-center">
                      <div className="col-4">
                        <img width="100%" src={product.thumbnail} />
                      </div>
                      <div className="col-8">
                        <p style={pStyle}>{product.title}</p>
                        <p
                          style={{
                            margin: "0",
                            color: "#20c997",
                            fontWeight: "bold",
                          }}
                        >
                          {product.price}
                        </p>
                        <p style={{ margin: "0" }}>Qty: {1}</p>
                      </div>
                    </div>
                  );
                })}
                <div
                  className="row justify-content-between pt-2 pb-2"
                  style={{
                    borderBottom: "1px solid #ededed",
                    borderTop: "1px solid #ededed",
                  }}
                >
                  <h6 className="col-4" style={{ margin: "0" }}>
                    Subtotal
                  </h6>
                  <p
                    className="col-8 text-end"
                    style={{
                      margin: "0",
                      fontSize: "1rem",
                      color: "#20c997",
                      fontWeight: "bold",
                    }}
                  >
                    {cart.total}
                  </p>
                </div>
              </div>
            </div>
            <div
              className="row mt-3 p-3"
              style={{
                backgroundColor: "white",
                boxShadow: "0 2px 5px 0 rgb(0 0 0 / 5%)",
                borderRadius: "5px",
              }}
            >
              <div className="col-12">
                <h6
                  className="pb-3"
                  style={{ borderBottom: "1px solid #ededed" }}
                >
                  Payment Methods
                </h6>
                <div className="row">
                  <div className="col-12">
                    <div className="row mb-2">
                      <div className="col-2">
                        <input
                          className="form-check-input"
                          type="radio"
                          name="flexRadioDefault"
                        />
                      </div>
                      <div className="col-3">
                        <img
                          width="100%"
                          src="https://www.myxprs.com/assets/imgs/icons/cash.png"
                        />
                      </div>
                      <div className="col">
                        <label
                          className="form-check-label"
                          for="flexRadioDefault2"
                        >
                          Cash on delivery
                        </label>
                      </div>
                    </div>
                    <div className="row mb-2">
                      <div className="col-2">
                        <input
                          className="form-check-input"
                          type="radio"
                          name="flexRadioDefault"
                        />
                      </div>
                      <div className="col-3">
                        <img
                          width="100%"
                          src="https://www.myxprs.com/assets/imgs/icons/visa.png"
                        />
                      </div>
                      <div className="col">
                        <label
                          className="form-check-label"
                          for="flexRadioDefault2"
                        >
                          Online Payment
                        </label>

                        {/* https://www.myxprs.com/assets/imgs/icons/misr.png */}
                      </div>
                    </div>
                    <div className="row mb-2">
                      <div className="col-2">
                        <input
                          className="form-check-input"
                          type="radio"
                          name="flexRadioDefault"
                        />
                      </div>
                      <div className="col-3">
                        <img
                          width="100%"
                          src=" https://www.myxprs.com/assets/imgs/icons/misr.png"
                        />
                      </div>
                      <div className="col">
                        <label
                          className="form-check-label"
                          for="flexRadioDefault2"
                        >
                          MISR Installment
                        </label>
                      </div>
                    </div>
                    <div className="row mt-5">
                      <button type="submit" className="btn btn-primary">
                        SAVE AND CONTINUE
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Checkout;
